(1,	0,	1,	'Home',	'',	'',	'',	'',	'e64120ba4a8c1437ab79e6289cd1817f',	0,	1,	1,	10,	1,	1,	'2024-02-07 12:26:11',	1,	'2024-07-18 14:14:23',	0,	NULL),
