(10,	0,	5,	'Account Registration',	'&lt;p&gt;Plans that start free&lt;/p&gt;',	'',	'',	'',	'fbd5daa3418134e522dd00d6d4ae02d1',	0,	1,	1,	6,	1,	1,	'2024-02-07 12:28:23',	1,	'2024-07-18 14:14:23',	0,	NULL),
(11,	0,	5,	'帳戶註冊',	'&lt;p&gt;免費開始的計劃&lt;/p&gt;',	'',	'',	'',	'fbd5daa3418134e522dd00d6d4ae02d1',	0,	1,	2,	6,	1,	1,	'2024-02-07 12:28:23',	1,	'2024-07-18 14:14:23',	0,	NULL),
(12,	0,	5,	'帐户註册',	'&lt;p&gt;免费开始的计划&lt;/p&gt;',	'',	'',	'',	'fbd5daa3418134e522dd00d6d4ae02d1',	0,	1,	3,	6,	1,	1,	'2024-02-07 12:28:23',	1,	'2024-07-18 14:14:23',	0,	NULL),
(13,	0,	6,	'Visa Submission',	'&lt;p&gt;It is ok that you submit a visa application by yourself, however you shall be aware of the risks of not having any helps by a migration professional. It may potentially cost you much more than the fee of the professional shall your visa get refused.&lt;/p&gt;\r\n&lt;p&gt;If you still prefer to Do-It-Yourself (DIY), try to get some helps from AI-mmi, our highly trained migration AI consultant.&lt;/p&gt;',	'',	'',	'',	'1096f87eaadb3c383575f897a30b9fe3',	0,	1,	1,	5,	1,	1,	'2024-02-07 12:29:19',	1,	'2024-07-18 14:14:23',	0,	NULL),
(14,	0,	6,	'簽證申請',	'&lt;p&gt;您可以自己提交簽證申請，但您要考慮沒有移民專業人士幫助的風險。 如果您的簽證被拒，您的花費用可能會比聘請專業人士的費用高得多。&lt;/p&gt;\r\n&lt;p&gt;如果您選擇自己申請(DIY)，請嘗試找我們訓練有素的AI移民顧問 AI-mmi 幫忙。&lt;/p&gt;',	'',	'',	'',	'1096f87eaadb3c383575f897a30b9fe3',	0,	1,	2,	5,	1,	1,	'2024-02-07 12:29:19',	1,	'2024-07-18 14:14:23',	0,	NULL),
(15,	0,	6,	'签证申请',	'&lt;p&gt;您可以自己提交签证申请，但您要考虑没有移民专业人士帮助的风险。 如果您的签证被拒，您的花费用可能会比聘请专业人士的费用高得多。&lt;/p&gt;\r\n&lt;p&gt;如果您选择自己申请(DIY)，请尝试找我们训练有素的AI移民顾问 AI-mmi 帮忙。&lt;/p&gt;',	'',	'',	'',	'1096f87eaadb3c383575f897a30b9fe3',	0,	1,	3,	5,	1,	1,	'2024-02-07 12:29:19',	1,	'2024-07-18 14:14:23',	0,	NULL),
