(39,	0,	13,	3,	'创业移民',	NULL,	NULL,	NULL,	NULL,	NULL,	'cf47fcf9551bf908466528739576207f',	0,	1,	3,	6,	1,	1,	'2024-06-11 13:16:56',	1,	'2024-06-11 13:16:56',	0,	NULL),
(40,	13,	14,	0,	'Start Up Visa',	'Start Up Visa',	'&lt;p&gt;This is a permanent residency visa of Canada. Visa applicant(s) may initial an eligible startup project in Canada to apply for this visa.&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;Visa requirements for the visa applicant:&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;process a post secondary qualification&lt;/li&gt;\r\n&lt;li&gt;meet the English requirements (e.g. score a 5 at IELTS)&lt;/li&gt;\r\n&lt;li&gt;holds at least 10% shares in the eligible project&lt;/li&gt;\r\n&lt;li&gt;be part of the project founding team&lt;/li&gt;\r\n&lt;/ul&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;Visa requirements for the project:&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;must have obtained the Letter of Support from an IRCC (Immigration, Refugees and Citizenship Canada) listed endorsing organization&lt;/li&gt;\r\n&lt;li&gt;must be innovative and benefitial to Canada&lt;/li&gt;\r\n&lt;li&gt;No more than 5 founding members in the team, each member may bring their families&lt;/li&gt;\r\n&lt;/ul&gt;',	'',	'',	'',	'1e9430000f8a49fe3e5b74bce8e92261',	0,	2,	1,	1,	1,	1,	'2024-06-11 13:40:15',	1,	'2024-06-11 13:41:47',	0,	NULL),
(41,	13,	14,	0,	'創業移民簽證',	'創業移民簽證',	'&lt;p&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;這是加拿大的永久居留簽證。簽證申請人可以在加拿大創立一個符合資格的項目來申請此簽證。&lt;/span&gt;&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;&lt;strong&gt;簽證申請人的簽證要求：&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;具中學後學歷&lt;/span&gt;&lt;/li&gt;\r\n&lt;li&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt; 滿足英語要求（例如雅思成績 5 分） &lt;/span&gt;&lt;/li&gt;\r\n&lt;li&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;持有合格項目至少10%的股份 &lt;/span&gt;&lt;/li&gt;\r\n&lt;li&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;成為專案創始團隊的一員 &lt;/span&gt;&lt;/li&gt;\r\n&lt;/ul&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;&lt;strong&gt;項目要求： &lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt; 必須已獲得 IRCC（加拿大移民、難民和公民部）列出的認可組織的支持函 &lt;/span&gt;&lt;/li&gt;\r\n&lt;li&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;必須具有創新性且對加拿大有利&lt;/span&gt;&lt;/li&gt;\r\n&lt;li&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;項目團隊不超過5名成員申請, 每人可帶家屬&lt;/span&gt;&lt;/li&gt;\r\n&lt;/ul&gt;',	'',	'',	'',	'1e9430000f8a49fe3e5b74bce8e92261',	0,	2,	2,	1,	1,	1,	'2024-06-11 13:40:15',	1,	'2024-06-11 13:41:47',	0,	NULL),
(42,	13,	14,	0,	'创业移民签证',	'创业移民签证',	'&lt;p&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;这是加拿大的永久居留签证。签证申请人可以在加拿大创立一个符合资格的项目来申请此签证。&lt;/span&gt;&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;&lt;strong&gt;签证申请人的签证要求：&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;具中学后学歷&lt;/span&gt;&lt;/li&gt;\r\n&lt;li&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt; 满足英语要求（例如雅思成绩 5 分） &lt;/span&gt;&lt;/li&gt;\r\n&lt;li&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;持有合格项目至少10%的股份 &lt;/span&gt;&lt;/li&gt;\r\n&lt;li&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;成为专案创始团队的一员 &lt;/span&gt;&lt;/li&gt;\r\n&lt;/ul&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;&lt;strong&gt;项目要求： &lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt; 必须已获得 IRCC（加拿大移民、难民和公民部）列出的认可组织的支持函 &lt;/span&gt;&lt;/li&gt;\r\n&lt;li&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;必须具有创新性且对加拿大有利&lt;/span&gt;&lt;/li&gt;\r\n&lt;li&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;项目团队不超过5名成员申请, 每人可带家属&lt;/span&gt;&lt;/li&gt;\r\n&lt;/ul&gt;',	'',	'',	'',	'1e9430000f8a49fe3e5b74bce8e92261',	0,	2,	3,	1,	1,	1,	'2024-06-11 13:40:15',	1,	'2024-06-11 13:41:47',	0,	NULL),
(43,	11,	15,	0,	'Subclass 189 Skilled Independent Visa',	'Subclass 189 Skilled Independent Visa',	'&lt;p&gt;The points-tested stream of skilled independent visa is a permanent visa, and no secured job offer is required to apply for the visa.&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;Visa requirements:&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;be invited to apply through an Expression of Interest (EOI)&lt;/li&gt;\r\n&lt;li&gt;have suitable skills assessment&lt;/li&gt;\r\n&lt;li&gt;below 45 years old&lt;/li&gt;\r\n&lt;li&gt;satisfy the points test with a minimum of 65 points&lt;/li&gt;\r\n&lt;li&gt;have Competent English (e.g. scoring 6 for all components of IELTS)&lt;/li&gt;\r\n&lt;li&gt;occupation is in the eligible list&lt;/li&gt;\r\n&lt;li&gt;meet the character and health requirements&lt;/li&gt;\r\n&lt;/ul&gt;',	'',	'',	'',	'4506297a697e69650cfc71a2015bf9b5',	0,	2,	1,	1,	1,	1,	'2024-06-11 14:47:14',	1,	'2024-06-11 14:47:14',	0,	NULL),
(44,	11,	15,	0,	'189技術移民簽證',	'189技術移民簽證',	'&lt;div id=&quot;tw-target-text-container&quot; class=&quot;tw-ta-container F0azHf tw-lfl&quot; tabindex=&quot;0&quot;&gt;\r\n&lt;p&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;這是透過計分制申請的技術獨立移民簽證，為永久居留簽證，申請該簽證不需要已獲澳洲的雇主聘請。 &lt;/span&gt;&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;&lt;strong&gt;簽證要求：&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;透過意向書 (EOI) 申請並獲得&lt;/span&gt;邀請&lt;/li&gt;\r\n&lt;li&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;有合適的技能評估&lt;/span&gt;&lt;/li&gt;\r\n&lt;li&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;45歲以下 &lt;/span&gt;&lt;/li&gt;\r\n&lt;li&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;取得計分制中至少 65 分 &lt;/span&gt;&lt;/li&gt;\r\n&lt;li&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;具有良好的英語能力（例如雅思所有部分均獲得 6 分） &lt;/span&gt;&lt;/li&gt;\r\n&lt;li&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;職業在合資格清單中 &lt;/span&gt;&lt;/li&gt;\r\n&lt;li&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;符合品格和健康要求&lt;/span&gt;&lt;/li&gt;\r\n&lt;/ul&gt;\r\n&lt;/div&gt;\r\n&lt;div id=&quot;tw-target-rmn-container&quot; class=&quot;tw-target-rmn tw-ta-container F0azHf tw-nfl&quot;&gt;&amp;nbsp;&lt;/div&gt;',	'',	'',	'',	'4506297a697e69650cfc71a2015bf9b5',	0,	2,	2,	1,	1,	1,	'2024-06-11 14:47:14',	1,	'2024-06-11 14:47:14',	0,	NULL),
(45,	11,	15,	0,	'189技术移民签证',	'189技术移民签证',	'&lt;div id=&quot;tw-target-text-container&quot; class=&quot;tw-ta-container F0azHf tw-lfl&quot; tabindex=&quot;0&quot;&gt;\r\n&lt;p&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;这是透过计分制申请的技术独立移民签证，为永久居留签证，申请该签证不需要已获澳洲的雇主聘请。 &lt;/span&gt;&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;&lt;strong&gt;签证要求：&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;透过意向书 (EOI) 申请并获得&lt;/span&gt;邀请&lt;/li&gt;\r\n&lt;li&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;有合适的技能评估&lt;/span&gt;&lt;/li&gt;\r\n&lt;li&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;45岁以下 &lt;/span&gt;&lt;/li&gt;\r\n&lt;li&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;取得计分制中至少 65 分 &lt;/span&gt;&lt;/li&gt;\r\n&lt;li&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;具有良好的英语能力（例如雅思所有部分均获得 6 分） &lt;/span&gt;&lt;/li&gt;\r\n&lt;li&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;职业在合资格清单中 &lt;/span&gt;&lt;/li&gt;\r\n&lt;li&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;符合品格和健康要求&lt;/span&gt;&lt;/li&gt;\r\n&lt;/ul&gt;\r\n&lt;/div&gt;\r\n&lt;div id=&quot;tw-target-rmn-container&quot; class=&quot;tw-target-rmn tw-ta-container F0azHf tw-nfl&quot;&gt;&amp;nbsp;&lt;/div&gt;',	'',	'',	'',	'4506297a697e69650cfc71a2015bf9b5',	0,	2,	3,	1,	1,	1,	'2024-06-11 14:47:14',	1,	'2024-06-11 14:47:14',	0,	NULL),
