(69,	0,	23,	3,	'技术移民计划',	NULL,	NULL,	NULL,	NULL,	NULL,	'dd1f65ffade86c58c6045bf7ab395969',	0,	1,	3,	10,	1,	1,	'2024-07-15 02:09:15',	1,	'2024-07-15 02:09:15',	0,	NULL),
(70,	23,	24,	0,	'Skilled Migration Program',	'Skilled Migration Program',	'&lt;p&gt;&lt;strong&gt;Three Federal Program through Express Entry&lt;/strong&gt;&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;1. Canada Experience Class&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;for skilled workers who have Canadian work experience&lt;/li&gt;\r\n&lt;li&gt;work experience must have been gained in the 3 years before application&lt;/li&gt;\r\n&lt;/ul&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;2. Federal Skilled Worker Program&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;for skilled workers with foreign work experience&lt;/li&gt;\r\n&lt;li&gt;must meet criteria for education and other factors&lt;/li&gt;\r\n&lt;/ul&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;3. Federal Skilled Trades Program&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;for skilled workers who are qualified in a skilled trade&lt;/li&gt;\r\n&lt;li&gt;must have a valid job offer or a certificate of qualification&lt;/li&gt;\r\n&lt;/ul&gt;\r\n&lt;p&gt;Applicants will be ranked in the Express Entry pool using the Comprehensive Ranking System (CRS) which is points-based. Only those who are ranked higher and score above the minimum points score will be invited to apply for a permanent visa.&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;Provincial Nominee Program (PNP)&lt;/strong&gt;&lt;/p&gt;\r\n&lt;p&gt;The provincial programs are for workers who have the skills, education, and work experience to become permanent residents of Canada and live in a specific province or territory. Each province and territory run its own streams that target different groups of people.&lt;/p&gt;',	'',	'',	'',	'a2b4d2dcf2d85a61957aa68f4e554426',	0,	2,	1,	1,	1,	1,	'2024-07-15 02:15:10',	1,	'2024-07-15 02:15:10',	0,	NULL),
(71,	23,	24,	0,	'技術移民計劃',	'技術移民計劃',	'&lt;p&gt;加拿大為技術移民提供永久居民定居的機會，主要通過技術移民項目實現。&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;聯邦項目 &amp;ndash; Express Entry&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;加拿大有3個通過 Express Entry 管理的移民項目:&lt;/strong&gt;&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;1. 加拿大工作經驗類別&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;適用於擁有加拿大工作經驗的技術移民&lt;/li&gt;\r\n&lt;li&gt;工作經驗必須在申請前3年內獲得&lt;/li&gt;\r\n&lt;/ul&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;2. 聯邦技術移民計劃&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;適用於擁有海外工作經驗的技術移民&lt;/li&gt;\r\n&lt;li&gt;必須滿足教育和其他因素的標準&lt;/li&gt;\r\n&lt;/ul&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;3. 聯邦技術工種移民計劃&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;適用於具備特定技術工種技能的移民&lt;/li&gt;\r\n&lt;li&gt;必須持有有效工作offer或職業資格證書&lt;/li&gt;\r\n&lt;/ul&gt;\r\n&lt;p&gt;申請人將根據綜合排名系統（CRS，積分制）在 Express Entry 申請池中排名。只有排名較高並超過最低分數門檻的申請人才會被邀請申請永久簽證。&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;省提名計劃（PNP）&lt;/strong&gt;&lt;/p&gt;\r\n&lt;p&gt;各省/地區的提名計劃針對具備技能、學歷和工作經驗的移民，幫助他們成為特定省/地區的永居居民。每個省/地區都有針對不同群體的項目。&lt;/p&gt;',	'',	'',	'',	'a2b4d2dcf2d85a61957aa68f4e554426',	0,	2,	2,	1,	1,	1,	'2024-07-15 02:15:10',	1,	'2024-07-15 02:15:10',	0,	NULL),
(72,	23,	24,	0,	'技术移民计划',	'技术移民计划',	'&lt;p&gt;加拿大为技术移民提供永久居民定居的机会，主要通过技术移民项目实现。&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;联邦项目 &amp;ndash; Express Entry&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;加拿大有3个通过 Express Entry 管理的移民项目:&lt;/strong&gt;&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;1. 加拿大工作经验类别&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;适用于拥有加拿大工作经验的技术移民&lt;/li&gt;\r\n&lt;li&gt;工作经验必须在申请前3年内获得&lt;/li&gt;\r\n&lt;/ul&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;2. 联邦技术移民计划&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;适用于拥有海外工作经验的技术移民&lt;/li&gt;\r\n&lt;li&gt;必须满足教育和其他因素的标准&lt;/li&gt;\r\n&lt;/ul&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;3. 联邦技术工种移民计划&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;适用于具备特定技术工种技能的移民&lt;/li&gt;\r\n&lt;li&gt;必须持有有效工作offer或职业资格证书&lt;/li&gt;\r\n&lt;/ul&gt;\r\n&lt;p&gt;申请人将根据综合排名系统（CRS，积分制）在 Express Entry 申请池中排名。只有排名较高并超过最低分数门槛的申请人才会被邀请申请永久签证。&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;省提名计划（PNP）&lt;/strong&gt;&lt;/p&gt;\r\n&lt;p&gt;各省/地区的提名计划针对具备技能、学歷和工作经验的移民，帮助他们成为特定省/地区的永居居民。每个省/地区都有针对不同群体的项目。&lt;/p&gt;',	'',	'',	'',	'a2b4d2dcf2d85a61957aa68f4e554426',	0,	2,	3,	1,	1,	1,	'2024-07-15 02:15:10',	1,	'2024-07-15 02:15:10',	0,	NULL),
(73,	11,	25,	0,	'Subclass 190 Skilled Independent Visa',	'Subclass 190 Skilled Independent Visa',	'&lt;p&gt;The points-tested stream of skilled independent visa is a permanent visa for skilled workers who are nominated by an Australian State or Territory government.&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;Visa requirements:&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;have an eligible occupation&lt;/li&gt;\r\n&lt;li&gt;satisfy the points test with a minimum of 65 points&lt;/li&gt;\r\n&lt;li&gt;below 45 years old&lt;/li&gt;\r\n&lt;li&gt;English proficiency level&amp;mdash;Competent (e.g. scoring 6 for all components of IELTS)&lt;/li&gt;\r\n&lt;li&gt;meet health and character requirements&lt;/li&gt;\r\n&lt;/ul&gt;',	'',	'',	'',	'cfcaf3c4d34de7301aef3ff797048a50',	0,	2,	1,	2,	1,	1,	'2024-07-15 02:22:17',	1,	'2024-07-15 02:22:17',	0,	NULL),
(74,	11,	25,	0,	'190技術移民簽證',	'190技術移民簽證',	'&lt;p&gt;這是透過計分制申請的技術獨立移民簽證，為由澳洲州或領地政府提名的永久居留簽證。&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;要求：&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;擁有符合資格的職業&lt;/li&gt;\r\n&lt;li&gt;至少獲得 65 分&lt;/li&gt;\r\n&lt;li&gt;年齡不超過 45 歲&lt;/li&gt;\r\n&lt;li&gt;雅思至少 6 分&lt;/li&gt;\r\n&lt;li&gt;滿足健康和品格要求&lt;/li&gt;\r\n&lt;/ul&gt;',	'',	'',	'',	'cfcaf3c4d34de7301aef3ff797048a50',	0,	2,	2,	2,	1,	1,	'2024-07-15 02:22:17',	1,	'2024-07-15 02:22:17',	0,	NULL),
(75,	11,	25,	0,	'190技术移民签证',	'190技术移民签证',	'&lt;p&gt;这是透过计分制申请的技术独立移民签证，为由澳洲州或领地政府提名的永久居留签证。&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;要求：&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;拥有符合资格的职业&lt;/li&gt;\r\n&lt;li&gt;至少获得 65 分&lt;/li&gt;\r\n&lt;li&gt;年龄不超过 45 岁&lt;/li&gt;\r\n&lt;li&gt;雅思至少 6 分&lt;/li&gt;\r\n&lt;li&gt;满足健康和品格要求&lt;/li&gt;\r\n&lt;/ul&gt;',	'',	'',	'',	'cfcaf3c4d34de7301aef3ff797048a50',	0,	2,	3,	2,	1,	1,	'2024-07-15 02:22:17',	1,	'2024-07-15 02:22:17',	0,	NULL),
(76,	11,	26,	0,	'Subclass 491 Skilled Independent Visa',	'Subclass 491 Skilled Independent Visa',	'&lt;p&gt;The points-tested stream of skilled independent visa is a temporary visa allows skilled workers live in a regional area of Australia for up to five years, with a pathway to transition to permanent residency through subclass 191 visa.&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;Visa requirements:&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;have an eligible occupation&lt;/li&gt;\r\n&lt;li&gt;satisfy the points test with a minimum of 65 points&lt;/li&gt;\r\n&lt;li&gt;below 45 years old&lt;/li&gt;\r\n&lt;li&gt;English proficiency level&amp;mdash;Competent (e.g. scoring 6 for all components of IELTS)&lt;/li&gt;\r\n&lt;li&gt;meet health and character requirements&lt;/li&gt;\r\n&lt;/ul&gt;',	'',	'',	'',	'af289e065eafa778d89771af4464aafd',	0,	2,	1,	3,	1,	1,	'2024-07-15 02:25:20',	1,	'2024-07-15 02:25:20',	0,	NULL),
(77,	11,	26,	0,	'491技術移民簽證',	'491技術移民簽證',	'&lt;p&gt;這是臨時居留簽證，允許技術移民在澳洲區域地區居住長達五年，並可透過 191 簽證申請永久居留資格。&lt;/p&gt;\r\n&lt;h5&gt;&amp;nbsp;&lt;/h5&gt;\r\n&lt;p&gt;&lt;strong&gt;要求：&lt;/strong&gt;&lt;/p&gt;\r\n&lt;div&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;擁有符合資格的職業&lt;/li&gt;\r\n&lt;li&gt;至少獲得 65 分&lt;/li&gt;\r\n&lt;li&gt;年齡不超過 45 歲&lt;/li&gt;\r\n&lt;li&gt;雅思至少 6 分&lt;/li&gt;\r\n&lt;li&gt;滿足健康和品格要求&lt;/li&gt;\r\n&lt;/ul&gt;\r\n&lt;/div&gt;',	'',	'',	'',	'af289e065eafa778d89771af4464aafd',	0,	2,	2,	3,	1,	1,	'2024-07-15 02:25:20',	1,	'2024-07-15 02:25:20',	0,	NULL),
(78,	11,	26,	0,	'491技术移民签证',	'491技术移民签证',	'&lt;p&gt;这是临时居留签证，允许技术移民在澳洲区域地区居住长达五年，并可透过 191 签证申请永久居留资格。&lt;/p&gt;\r\n&lt;h5&gt;&amp;nbsp;&lt;/h5&gt;\r\n&lt;p&gt;&lt;strong&gt;要求：&lt;/strong&gt;&lt;/p&gt;\r\n&lt;div&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;拥有符合资格的职业&lt;/li&gt;\r\n&lt;li&gt;至少获得 65 分&lt;/li&gt;\r\n&lt;li&gt;年龄不超过 45 岁&lt;/li&gt;\r\n&lt;li&gt;雅思至少 6 分&lt;/li&gt;\r\n&lt;li&gt;满足健康和品格要求&lt;/li&gt;\r\n&lt;/ul&gt;\r\n&lt;/div&gt;',	'',	'',	'',	'af289e065eafa778d89771af4464aafd',	0,	2,	3,	3,	1,	1,	'2024-07-15 02:25:20',	1,	'2024-07-15 02:25:20',	0,	NULL),
